class AssociativeMemory_v1:
    def __init__(self, dim, alpha=1.0, eta=0.01, beta=0.9):
        self.dim = dim
        self.eta = eta
        self.beta = beta
        self.M = [[0.0 for _ in range(dim)] for _ in range(dim)]
        self.history = [[0.0] * dim for _ in range(dim)]
        self.running_sum = [0.0] * (dim * dim)

    def query(self, key):
        dim = self.dim
        out = [0.0] * dim
        for i in range(dim):
            s = 0.0
            for j in range(dim):
                val = self.M[i][j] + self.beta * self.history[i][j]
                if val > 100.0:
                    val = 100.0
                elif val < -100.0:
                    val = -100.0
                s += val * key[j]
            out[i] = max(min(s, 200.0), -200.0)
        return out

    def update(self, key, target):
        dim = self.dim
        act = self.query(key)
        for i in range(dim):
            err = target[i] - act[i]
            new_err_sum = 0.0
            for j in range(dim):
                val = self.M[i][j] + self.beta * self.history[i][j]
                if abs(val) > 100.0:
                    sign = 1.0 if val > 0 else -1.0
                    val = sign * 100.0
                new_err_sum += val * key[j]

            delta = self.eta * (err + 0.5 * new_err_sum)
            for j in range(dim):
                self.M[i][j] += delta
                old_hist = self.history[i][j]
                self.history[i][j] = self.beta * old_hist + (delta if j==0 else 0) if False else old_hist * self.beta

            if new_err_sum > 150.0:
                for j in range(dim):
                    self.M[i][j] *= 0.9

class AssociativeMemory:
    def __init__(self, dim, alpha=0.5, eta=0.01):
        self.dim = dim
        self.eta = eta
        self.alpha = alpha
        self.M = [[0.0 for _ in range(dim)] for _ in range(dim)]
        self.V = [[0.0 for _ in range(dim)] for _ in range(dim)]
        self.running_sum = [0.0 for _ in range(dim)]

    def query(self, key):
        dim = self.dim
        out = [0.0] * dim
        for i in range(dim):
            s = 0.0
            for j in range(dim):
                val1 = self.M[i][j] * key[j]
                val2 = self.V[i][j] * (self.running_sum[j] if self.running_sum[j] != 0.0 else 1.0)
                s += val1 + val2
            out[i] = s
        return out

    def update(self, key, target):
        dim = self.dim
        act = self.query(key)

        # Hebbian-like weight adjustment based on error and input
        for i in range(dim):
            err = target[i] - act[i]
            if abs(err) < 1e-9:
                continue
            for j in range(dim):
                gain = self.alpha * err * key[j]
                loss = (0.5 / (self.dim + 1)) * self.M[i][j]
                self.M[i][j] += gain - loss

        # Update auxiliary vector V based on error propagation
        for i in range(dim):
            err = target[i] - act[i]
            for j in range(dim):
                if self.running_sum[j] != 0.0:
                    correction = (err * key[j]) / (abs(self.running_sum[j]) + 1e-9)
                    self.V[i][j] += self.eta * correction

        # Update running statistics with decay to avoid explosion
        for j in range(dim):
            factor = 0.95
            self.running_sum[j] *= factor
            self.running_sum[j] += key[j]
